pure fn char_frequency(s: Text) -> [Text] {
    chars = []
    counts = []
    for c in split(s, "") {
        found = false
        for i in range(0, length(chars)) {
            if get(chars, i) == c {
                counts = append(counts, 0)  // placeholder to keep length consistent
                counts = replace(counts, i, get(counts, i) + 1)
                found = true
                break
            }
        }
        if not found {
            chars = append(chars, c)
            counts = append(counts, 1)
        }
    }
    result = []
    for i in range(0, length(chars)) {
        pair = join([get(chars, i), ":", to_text(get(counts, i))], "")
        result = append(result, pair)
    }
    return result
}

entry main(x: Text) {
    freqs = char_frequency("mississippi")
    return join(freqs, ", ")
}

