intent classify_pass_fail(record: Text) -> Text {
    goal: classify each person as passed or failed based on score 80 or above
}

pure fn parse_scores(input: Text) -> [Text] {
    return split(input, ",")
}

pure fn extract_name_score(entry: Text) -> [Text] {
    return split(entry, ":")
}

pure fn passed(score_text: Text) -> Boolean {
    score = to_number(score_text)
    if is_error(score) { return false }
    return unwrap(score) >= 80
}

pure fn classify_entries(entries: [Text]) -> [Text] {
    results = []
    for e in entries {
        parts = extract_name_score(e)
        name = get(parts, 0)
        score_text = get(parts, 1)
        if passed(score_text) {
            results = append(results, join([name, ": passed"], ""))
        } else {
            results = append(results, join([name, ": failed"], ""))
        }
    }
    return results
}

entry main(x: Text) {
    entries = parse_scores(x)
    classified = classify_entries(entries)
    return join(classified, ", ")
}

