intent recommend_purchase(csv: Text, budget: Text) -> Text {
    goal: recommend a product to buy from csv within budget
}
pure fn csv_to_rows_simple(csv: Text) -> [[Text]] {
    return split(csv, "\n")
}
pure fn parse_price(price_text: Text) -> Number {
    return to_number(price_text)
}
pure fn find_affordable_products(rows: [[Text]], budget: Number) -> [Text] {
    affordable = []
    for i in range(1, length(rows)) {
        row = get(rows, i)
        price = parse_price(get(row, 1))
        if price <= budget {
            affordable = append(affordable, get(row, 0))
        }
    }
    return affordable
}
pure fn recommend(affordable: [Text]) -> Text {
    if length(affordable) == 0 {
        return "No products available within budget"
    }
    return get(affordable, 0)
}
entry main(x: Text) {
