intent assess_timeline(days: Number) -> Text {
    goal: suggest if timeline is reasonable based on days difference
}
pure fn days_between(dates: [Text]) -> Number {
    if length(dates) < 2 { return 0 }
    y1 = to_number(slice(get(dates, 0), 0, 4))
    m1 = to_number(slice(get(dates, 0), 5, 7))
    day1 = to_number(slice(get(dates, 0), 8, 10))
    y2 = to_number(slice(get(dates, 1), 0, 4))
    m2 = to_number(slice(get(dates, 1), 5, 7))
    day2 = to_number(slice(get(dates, 1), 8, 10))
    // approximate days difference ignoring time zones and leap years
    return (y2 - y1) * 365 + (m2 - m1) * 30 + (day2 - day1)
}
entry main(x: Text) {
    dates = parse_dates(x)
    diff = days_between(dates)
    suggestion = assess_timeline(diff)
    return join(["Days between: ", to_text(diff), ". Suggestion: ", suggestion], "")
}

intent describe_pattern(freqs: Text) -> Text {
