}

pure fn char_frequencies(s: Text) -> Text {
    counts = []
    chars = []
    for c in split(s, "") {
        found = false
        for i in range(0, length(chars)) {
            if get(chars, i) == c {
                counts[i] = counts[i] + 1
                found = true
                break
            }
        }
        if not found {
            chars = append(chars, c)
            counts = append(counts, 1)
        }
    }
    pairs = []
    for i in range(0, length(chars)) {
        pair = join([get(chars, i), ":", to_text(get(counts, i))], "")
        pairs = append(pairs, pair)
    }
    return join(pairs, ", ")
}

entry main(x: Text) {
    text = "hello world"
    freqs = char_frequencies(text)
    description = describe_pattern(freqs)
    return join([freqs, "\n", description], "")
}

intent explain_percentile(value: Number, sorted_list: [Number]) -> Text {
