pure fn percentile_rank(value: Number, sorted_list: [Number]) -> Number {
    n = length(sorted_list)
    count_less = 0
    for x in sorted_list {
        if x < value { count_less = count_less + 1 }
    }
    return (count_less * 100) / n
}
pure fn sort_desc(nums: [Number]) -> [Number] {
    sorted_asc = sort(nums)
    return reverse(sorted_asc)
}
entry main(x: Text) {
