intent describe_pattern(pairs: Text) -> Text {
    goal: describe the geographic pattern of cities sorted by latitude
}
pure fn parse_pairs(input: Text) -> [[Text, Number]] {
    parts = split(input, ",")
    result = []
    for part in parts {
        pair = split(part, ":")
        city = get(pair, 0)
        lat = to_number(get(pair, 1))
        result = append(result, [city, lat])
    }
    return result
}
pure fn sort_by_latitude(pairs: [[Text, Number]]) -> [[Text, Number]] {
    // simple bubble sort by latitude ascending
    n = length(pairs)
    sorted_pairs = pairs
    for i in range(0, n) {
        for j in range(0, n - i - 1) {
            lat_j = get(get(sorted_pairs, j), 1)
            lat_j1 = get(get(sorted_pairs, j + 1), 1)
            if lat_j > lat_j1 {
                temp = get(sorted_pairs, j)
                sorted_pairs = append(slice(sorted_pairs, 0, j), get(sorted_pairs, j + 1))
                sorted_pairs = append(sorted_pairs, temp)
                sorted_pairs = append(sorted_pairs, slice(sorted_pairs, j + 2, n))
            }
        }
    }
    return sorted_pairs
}
entry main(x: Text) {
    pairs = parse_pairs(x)
    sorted_pairs = sort_by_latitude(pairs)
    description = describe_pattern(join([to_text(get(get(sorted_pairs, 0), 0)), ", ", to_text(get(get(sorted_pairs, 1), 0)), ", ", to_text(get(get(sorted_pairs, 2), 0))], ", "))
    return join([join([to_text(get(get(sorted_pairs, 0), 0)), ":", to_text(get(get(sorted_pairs, 0), 1))], " "), ", ", join([to_text(get(get(sorted_pairs, 1), 0)), ":", to_text(get(get(sorted_pairs, 1), 1))], " "), ", ", join([to_text(get(get(sorted_pairs, 2), 0)), ":", to_text(get(get(sorted_pairs, 2), 1))], " "), "\n", description], "")
}

